    <script>
     var myclick = function(v) {
      var divs = document.getElementsByClassName("tab");
      for (var i = 0; i < divs.length; i++) {
        var divv = divs[i];
        if (divv == document.getElementById("tab" + v + "_content")) {
          divv.style.display = "block";
        } else {
          divv.style.display = "none";
        }
      }
    }
    $(document).ready(function() {
      $('#jk .jk').click(function() {
        $(this).siblings().removeClass('active-jk');
        $(this).addClass('active-jk');
      })
    });
  </script>
  <script>
		var url =location.href;
		var typeNum=url.split('?')[1].split("=")[1];
		if(typeNum==typeNum){
			$('#jk button').eq(typeNum-1).addClass('active-jk').siblings().removeClass('active-jk');
			$('.wanfa .qiehuan').eq(typeNum-1).show().siblings().hide();
		}
